 15→// LifecycleEnv provides a full-lifecycle test environment: a git repo with
 16→// `entire enable` already run, ready for agent prompts and checkpoint assertions.
 17→type LifecycleEnv struct {
 18→	Dir     string   // repo root (temp dir)
 19→	HomeDir string   // isolated HOME
 20→	Env     []string // environment variables for subprocesses
 21→	Agent   string   // agent name (e.g. "kiro")
 22→}
 23→
 24→// NewLifecycleEnv creates a temp git repo, writes an initial commit, and runs
 25→// `entire enable --agent <agentName>`. It also writes .entire/settings.json
 26→// with external_agents enabled.
 27→func NewLifecycleEnv(t *testing.T, agentName string) *LifecycleEnv {
 28→	t.Helper()
 29→
 30→	dir := t.TempDir()
 31→	homeDir := t.TempDir()
 32→
 33→	env := baseEnv(dir, homeDir)
 34→
 35→	le := &LifecycleEnv{
 36→		Dir:     dir,
 37→		HomeDir: homeDir,
 38→		Env:     env,
 39→		Agent:   agentName,
 40→	}
 41→
 42→	// Initialize git repo with a seed commit.
 43→	le.Git(t, "init")
 44→	le.Git(t, "config", "user.email", "test@test.com")
 45→	le.Git(t, "config", "user.name", "Test User")
 46→	le.WriteFile(t, "README.md", "# test repo\n")
 47→	le.Git(t, "add", ".")
 48→	le.Git(t, "commit", "-m", "initial commit")
 49→
 50→	// Write .entire/settings.json with external_agents enabled.
 51→	le.MkdirAll(t, ".entire")
 52→	le.WriteFile(t, ".entire/settings.json", `{"external_agents":true}`)
 53→
 54→	// Run entire enable.
 55→	EntireEnable(t, dir, agentName, env)
 56→
 57→	return le
 58→}
 59→
 60→// Git runs a git command in the repo dir; fails the test on error.
 61→func (le *LifecycleEnv) Git(t *testing.T, args ...string) {
 62→	t.Helper()
 63→	cmd := exec.Command("git", args...)
 64→	cmd.Dir = le.Dir
 65→	cmd.Env = le.Env
 66→	if out, err := cmd.CombinedOutput(); err != nil {
 67→		t.Fatalf("git %s failed: %v\n%s", strings.Join(args, " "), err, out)
 68→	}
 69→}
 70→
 71→// GitOutput runs a git command and returns its combined output.
 72→func (le *LifecycleEnv) GitOutput(t *testing.T, args ...string) string {
 73→	t.Helper()
 74→	cmd := exec.Command("git", args...)
 75→	cmd.Dir = le.Dir
 76→	cmd.Env = le.Env
 77→	out, err := cmd.CombinedOutput()
 78→	if err != nil {
 79→		t.Fatalf("git %s failed: %v\n%s", strings.Join(args, " "), err, out)
 80→	}
 81→	return string(out)
 82→}
 83→
 84→// RunKiroPrompt runs `kiro-cli-chat chat --no-interactive --trust-all-tools --agent entire <prompt>`.
 85→func (le *LifecycleEnv) RunKiroPrompt(t *testing.T, prompt string) error {
 86→	t.Helper()
 87→	bin, err := exec.LookPath("kiro-cli-chat")
 88→	if err != nil {
 89→		t.Fatalf("kiro-cli-chat not in PATH: %v", err)
 90→	}
 91→	cmd := exec.Command(bin, "chat", "--no-interactive", "--trust-all-tools", "--agent", "entire", prompt)
 92→	cmd.Dir = le.Dir
 93→	cmd.Env = le.Env
 94→	out, err := cmd.CombinedOutput()
 95→	if err != nil {
 96→		t.Logf("kiro-cli-chat output:\n%s", out)
 97→		return fmt.Errorf("kiro-cli-chat: %w", err)
 98→	}
 99→	t.Logf("kiro-cli-chat output:\n%s", out)
100→	return nil
101→}
102→
103→// FileExists checks whether relPath exists in the repo dir.
104→func (le *LifecycleEnv) FileExists(relPath string) bool {
105→	_, err := os.Stat(filepath.Join(le.Dir, relPath))
106→	return err == nil
107→}
108→
109→// WriteFile writes content to relPath inside the repo dir.
110→func (le *LifecycleEnv) WriteFile(t *testing.T, relPath, content string) {
111→	t.Helper()
112→	abs := filepath.Join(le.Dir, relPath)
113→	if err := os.MkdirAll(filepath.Dir(abs), 0o750); err != nil {
114→		t.Fatalf("mkdir for %s: %v", relPath, err)
115→	}
116→	if err := os.WriteFile(abs, []byte(content), 0o600); err != nil {
117→		t.Fatalf("write %s: %v", relPath, err)
118→	}
119→}
120→
121→// ReadFile reads a file from relPath inside the repo dir.
122→func (le *LifecycleEnv) ReadFile(t *testing.T, relPath string) string {
123→	t.Helper()
124→	data, err := os.ReadFile(filepath.Join(le.Dir, relPath))
125→	if err != nil {
126→		t.Fatalf("read %s: %v", relPath, err)
127→	}
128→	return string(data)
129→}
130→
131→// MkdirAll creates a directory (and parents) relative to the repo root.
132→func (le *LifecycleEnv) MkdirAll(t *testing.T, relPath string) {
133→	t.Helper()
134→	if err := os.MkdirAll(filepath.Join(le.Dir, relPath), 0o750); err != nil {
135→		t.Fatalf("mkdir %s: %v", relPath, err)
136→	}
137→}
138→
139→// AbsPath returns the absolute path for a relative path in the repo.
140→func (le *LifecycleEnv) AbsPath(relPath string) string {
141→	return filepath.Join(le.Dir, relPath)
142→}
143→
144→// WaitForCheckpoint polls for a checkpoint on the entire/checkpoints/v1 branch.
145→// It checks for new commits on that branch within the given timeout.
146→func WaitForCheckpoint(t *testing.T, le *LifecycleEnv, timeout time.Duration) {
147→	t.Helper()
148→	deadline := time.Now().Add(timeout)
149→	for time.Now().Before(deadline) {
150→		cmd := exec.Command("git", "rev-parse", "--verify", "entire/checkpoints/v1")
151→		cmd.Dir = le.Dir
152→		cmd.Env = le.Env
153→		if err := cmd.Run(); err == nil {
154→			t.Log("checkpoint branch found")
155→			return
156→		}
157→		time.Sleep(500 * time.Millisecond)
158→	}
159→	t.Fatal("timed out waiting for checkpoint branch entire/checkpoints/v1")
160→}
161→
162→// GetCheckpointTrailer extracts the Entire-Checkpoint trailer from a commit ref.
163→func GetCheckpointTrailer(t *testing.T, le *LifecycleEnv, ref string) string {
164→	t.Helper()
165→	out := le.GitOutput(t, "log", "-1", "--format=%B", ref)
166→	for _, line := range strings.Split(out, "\n") {
167→		if strings.HasPrefix(line, "Entire-Checkpoint:") {
168→			return strings.TrimSpace(strings.TrimPrefix(line, "Entire-Checkpoint:"))
169→		}
170→	}
171→	return ""
172→}
173→
174→// AssertFileExists fails the test if no file matches relPath in the repo.
175→func AssertFileExists(t *testing.T, le *LifecycleEnv, relPath string) {
176→	t.Helper()
177→	if !le.FileExists(relPath) {
178→		t.Errorf("expected file %s to exist", relPath)
179→	}
180→}
181→
182→// requireEntire fails or skips the test if the entire binary is not available.
183→// When E2E_REQUIRE_LIFECYCLE=1 (set by `make test-e2e-lifecycle`), it fails
184→// instead of skipping so you know immediately that your environment is missing deps.
185→func requireEntire(t *testing.T) {
186→	t.Helper()
187→	if !EntireAvailable() {
188→		const msg = "entire binary not available (set E2E_ENTIRE_BIN or install entire)"
189→		if os.Getenv("E2E_REQUIRE_LIFECYCLE") == "1" {
190→			t.Fatal(msg)
191→		}
192→		t.Skip("skipping: " + msg)
193→	}
194→}
195→
196→// requireKiroCLI fails or skips the test if kiro-cli-chat is not in PATH.
197→// When E2E_REQUIRE_LIFECYCLE=1, it fails instead of skipping.
198→func requireKiroCLI(t *testing.T) {
199→	t.Helper()
200→	if _, err := exec.LookPath("kiro-cli-chat"); err != nil {
201→		const msg = "kiro-cli-chat not in PATH"
202→		if os.Getenv("E2E_REQUIRE_LIFECYCLE") == "1" {
203→			t.Fatal(msg)
204→		}
205→		t.Skip("skipping: " + msg)
206→	}
207→}
