 10→// HookInput builds stdin payloads for hook-related subcommands.
 11→type HookInput struct {
 12→	HookType   string                 `json:"hook_type,omitempty"`
 13→	SessionID  string                 `json:"session_id,omitempty"`
 14→	SessionRef string                 `json:"session_ref,omitempty"`
 15→	Timestamp  string                 `json:"timestamp,omitempty"`
 16→	UserPrompt string                 `json:"user_prompt,omitempty"`
 17→	ToolName   string                 `json:"tool_name,omitempty"`
 18→	ToolUseID  string                 `json:"tool_use_id,omitempty"`
 19→	ToolInput  json.RawMessage        `json:"tool_input,omitempty"`
 20→	RawData    map[string]interface{} `json:"raw_data,omitempty"`
 21→}
 22→
 23→// JSON returns the JSON-encoded string for use as stdin.
 24→func (h HookInput) JSON(t *testing.T) string {
 25→	t.Helper()
 26→	data, err := json.Marshal(h)
 27→	if err != nil {
 28→		t.Fatalf("marshal HookInput: %v", err)
 29→	}
 30→	return string(data)
 31→}
 32→
 33→// ParseHookInput builds stdin payloads for the parse-hook subcommand.
 34→type ParseHookInput struct {
 35→	HookEventName string          `json:"hook_event_name,omitempty"`
 36→	CWD           string          `json:"cwd,omitempty"`
 37→	Prompt        string          `json:"prompt,omitempty"`
 38→	ToolName      string          `json:"tool_name,omitempty"`
 39→	ToolInput     json.RawMessage `json:"tool_input,omitempty"`
 40→}
 41→
 42→// JSON returns the JSON-encoded string.
 43→func (p ParseHookInput) JSON(t *testing.T) string {
 44→	t.Helper()
 45→	data, err := json.Marshal(p)
 46→	if err != nil {
 47→		t.Fatalf("marshal ParseHookInput: %v", err)
 48→	}
 49→	return string(data)
 50→}
 51→
 52→// KiroTranscript builds Kiro-format transcript files for testing.
 53→type KiroTranscript struct {
 54→	ConversationID string              `json:"conversation_id"`
 55→	History        []kiroHistoryEntry  `json:"history"`
 56→}
 57→
 58→type kiroHistoryEntry struct {
 59→	User      kiroUserMessage `json:"user"`
 60→	Assistant json.RawMessage `json:"assistant"`
 61→}
 62→
 63→type kiroUserMessage struct {
