594→	// First install
595→	var resp1 struct {
596→		HooksInstalled int `json:"hooks_installed"`
597→	}
598→	env.Runner.RunJSON(t, &resp1, "", "install-hooks")
599→	if resp1.HooksInstalled == 0 {
