 64→// ExternalAgent is an optional interface for agents discovered via the
 65→// external agent protocol (entire-agent-* binaries). SetupRepo uses this
 66→// to pre-configure external_agents in settings before running `entire enable`.
 67→type ExternalAgent interface {
 68→	IsExternalAgent() bool
 69→}
 70→
 71→var registry []Agent
 72→var gates = map[string]chan struct{}{}
 73→
 74→func Register(a Agent) {
 75→	registry = append(registry, a)
 76→}
 77→
 78→// RegisterGate sets a concurrency limit for an agent's tests.
 79→// Tests call AcquireSlot/ReleaseSlot to respect this limit.
 80→// The limit can be overridden via E2E_CONCURRENT_TEST_LIMIT.
 81→func RegisterGate(name string, defaultMax int) {
 82→	max := defaultMax
 83→	if v, err := strconv.Atoi(os.Getenv("E2E_CONCURRENT_TEST_LIMIT")); err == nil && v > 0 {
 84→		max = v
 85→	}
 86→	gates[name] = make(chan struct{}, max)
 87→}
 88→
 89→// AcquireSlot blocks until a test slot is available for the agent or the
 90→// context is cancelled. Returns a non-nil error if the context expires
 91→// before a slot opens.
 92→func AcquireSlot(ctx context.Context, a Agent) error {
 93→	g, ok := gates[a.Name()]
 94→	if !ok {
 95→		return nil
 96→	}
 97→	select {
 98→	case g <- struct{}{}:
 99→		return nil
100→	case <-ctx.Done():
101→		return ctx.Err()
102→	}
103→}
104→
105→// ReleaseSlot frees a test slot for the agent.
106→func ReleaseSlot(a Agent) {
107→	if g, ok := gates[a.Name()]; ok {
108→		<-g
109→	}
110→}
111→
112→func All() []Agent {
113→	return registry
114→}
115→
116→// filterEnv returns env with entries matching any of the given variable names
117→// removed. Used to strip test-only overrides (e.g. ENTIRE_TEST_TTY) from agent
118→// processes so they exercise real detection paths.
119→func filterEnv(env []string, names ...string) []string {
120→	out := make([]string, 0, len(env))
121→	for _, e := range env {
122→		skip := false
123→		for _, name := range names {
124→			if strings.HasPrefix(e, name+"=") {
125→				skip = true
126→				break
127→			}
128→		}
129→		if !skip {
130→			out = append(out, e)
131→		}
132→	}
133→	return out
134→}
