  1→package agents
  2→
  3→import (
  4→	"fmt"
  5→	"os"
  6→	"os/exec"
  7→	"regexp"
  8→	"strings"
  9→	"time"
 10→)
 11→
 12→// TmuxSession implements Session using tmux for PTY-based interactive agents.
 13→type TmuxSession struct {
 14→	name         string
 15→	stableAtSend string   // stable content snapshot when Send was last called
 16→	cleanups     []func() // run on Close
 17→}
 18→
 19→// OnClose registers a function to run when the session is closed.
 20→func (s *TmuxSession) OnClose(fn func()) {
 21→	s.cleanups = append(s.cleanups, fn)
 22→}
 23→
 24→// NewTmuxSession creates a new tmux session running the given command in dir.
 25→// unsetEnv lists environment variable names to strip from the session.
 26→//
 27→// The command is wrapped with `env` to propagate PATH from the current process.
 28→// tmux sessions inherit the tmux server's environment (not the client's), so
 29→// without this, binaries added to PATH by the test runner (e.g., freshly built
 30→// `entire` and `vogon`) would not be found inside the session.
 31→func NewTmuxSession(name string, dir string, unsetEnv []string, command string, args ...string) (*TmuxSession, error) {
 32→	s := &TmuxSession{name: name}
 33→
 34→	tmuxArgs := []string{"new-session", "-d", "-s", name, "-c", dir}
 35→	// Build a shell command string using `env` to:
 36→	//   1. Propagate PATH from the current process (tmux server may have stale PATH)
 37→	//   2. Unset variables listed in unsetEnv
 38→	// All arguments are shell-quoted to prevent injection or splitting.
 39→	// PATH is always forwarded from the current process so that the freshly-built
 40→	// "entire" binary (prepended to PATH by main_test.go) is available inside the
 41→	// tmux session. Without this, tmux inherits the server's environment which may
 42→	// have an older binary (or none at all).
 43→	var parts []string
 44→	parts = append(parts, "env")
 45→	// Options (-u) must precede variable assignments for BSD env on macOS.
 46→	for _, v := range unsetEnv {
 47→		parts = append(parts, "-u", shellQuote(v))
 48→	}
 49→	parts = append(parts, "PATH="+shellQuote(os.Getenv("PATH")))
 50→	parts = append(parts, shellQuote(command))
 51→	for _, a := range args {
 52→		parts = append(parts, shellQuote(a))
 53→	}
 54→	tmuxArgs = append(tmuxArgs, strings.Join(parts, " "))
 55→
 56→	cmd := exec.Command("tmux", tmuxArgs...)
 57→	if out, err := cmd.CombinedOutput(); err != nil {
 58→		return nil, fmt.Errorf("tmux new-session: %w\n%s", err, out)
 59→	}
 60→	// Keep the pane around after the command exits so we can capture error output.
 61→	setCmd := exec.Command("tmux", "set-option", "-t", name, "remain-on-exit", "on")
 62→	_ = setCmd.Run()
 63→	return s, nil
 64→}
 65→
 66→func (s *TmuxSession) Send(input string) error {
 67→	preSend := stableContent(s.Capture())
 68→	// Send text and Enter separately — Claude's TUI can swallow Enter
 69→	// if it arrives before the input handler finishes processing the text.
 70→	if err := s.SendKeys(input); err != nil {
 71→		return err
 72→	}
 73→	time.Sleep(200 * time.Millisecond)
 74→	if err := s.SendKeys("Enter"); err != nil {
 75→		return err
 76→	}
 77→
 78→	// Wait for the terminal to reflect the echoed input, then snapshot.
 79→	// This ensures WaitFor compares against post-echo content, preventing
 80→	// false matches on prompt characters (e.g. ❯) in the echoed input.
 81→	deadline := time.Now().Add(5 * time.Second)
 82→	for time.Now().Before(deadline) {
 83→		time.Sleep(200 * time.Millisecond)
 84→		current := stableContent(s.Capture())
 85→		if current != preSend {
 86→			s.stableAtSend = current
 87→			return nil
 88→		}
 89→	}
 90→	s.stableAtSend = stableContent(s.Capture())
 91→	return nil
 92→}
 93→
 94→// SendKeys sends raw tmux key names without appending Enter.
 95→func (s *TmuxSession) SendKeys(keys ...string) error {
 96→	args := append([]string{"send-keys", "-t", s.name}, keys...)
 97→	cmd := exec.Command("tmux", args...)
 98→	out, err := cmd.CombinedOutput()
 99→	if err != nil {
100→		return fmt.Errorf("tmux send-keys: %w\n%s", err, out)
101→	}
102→	return nil
103→}
104→
105→const (
106→	settleTime   = 2 * time.Second
107→	pollInterval = 500 * time.Millisecond
108→)
109→
110→// stableContent returns the content with the last few lines stripped,
111→// so that TUI status bar updates don't prevent the settle timer.
112→func stableContent(content string) string {
113→	lines := strings.Split(content, "\n")
114→	if len(lines) > 3 {
115→		lines = lines[:len(lines)-3]
116→	}
117→	return strings.Join(lines, "\n")
118→}
119→
120→func (s *TmuxSession) WaitFor(pattern string, timeout time.Duration) (string, error) {
121→	re, err := regexp.Compile(pattern)
122→	if err != nil {
123→		return "", fmt.Errorf("invalid pattern: %w", err)
124→	}
125→
126→	deadline := time.Now().Add(timeout)
127→	var matchedAt time.Time
128→	var lastStable string
129→	contentChanged := s.stableAtSend == "" // skip change requirement for initial waits
130→
131→	for time.Now().Before(deadline) {
132→		content := s.Capture()
133→		stable := stableContent(content)
134→
135→		// Bail early if the process has exited and the pattern doesn't match.
136→		// remain-on-exit keeps the pane alive, so without this check we'd
137→		// poll a dead pane for the full timeout duration.
138→		if !re.MatchString(content) {
139→			if s.IsPaneDead() {
140→				return content, fmt.Errorf("process exited while waiting for %q\n--- pane content ---\n%s\n--- end pane content ---", pattern, content)
141→			}
142→			// Pattern lost — reset
143→			matchedAt = time.Time{}
144→			lastStable = ""
145→			time.Sleep(pollInterval)
146→			continue
147→		}
148→
149→		// Detect content change since Send was called
150→		if !contentChanged && stable != s.stableAtSend {
151→			contentChanged = true
152→		}
153→
154→		if stable != lastStable {
155→			// Pattern matches but content is still changing — reset settle timer
156→			matchedAt = time.Now()
157→			lastStable = stable
158→			time.Sleep(pollInterval)
159→			continue
160→		}
161→
162→		// Pattern matches and content hasn't changed since matchedAt.
163→		// Only settle if content changed at least once after Send
164→		// (prevents false settle on echoed input before agent starts).
165→		if contentChanged && time.Since(matchedAt) >= settleTime {
166→			return content, nil
167→		}
168→
169→		time.Sleep(pollInterval)
170→	}
171→	content := s.Capture()
172→	return content, fmt.Errorf("timed out waiting for %q after %s\n--- pane content ---\n%s\n--- end pane content ---", pattern, timeout, content)
173→}
174→
175→// IsPaneDead returns true if the process inside the tmux pane has exited.
176→// This relies on the remain-on-exit option being set (which NewTmuxSession does).
177→func (s *TmuxSession) IsPaneDead() bool {
178→	cmd := exec.Command("tmux", "display-message", "-t", s.name, "-p", "#{pane_dead}")
179→	out, err := cmd.Output()
180→	if err != nil {
181→		// If tmux itself fails (e.g. session/pane no longer exists),
182→		// treat it as dead so WaitFor doesn't poll until timeout.
183→		return true
184→	}
185→	return strings.TrimSpace(string(out)) == "1"
186→}
187→
188→func (s *TmuxSession) Capture() string {
189→	cmd := exec.Command("tmux", "capture-pane", "-t", s.name, "-p")
190→	out, _ := cmd.Output()
191→	return strings.TrimRight(string(out), "\n")
192→}
193→
194→func (s *TmuxSession) Close() error {
195→	for _, fn := range s.cleanups {
196→		fn()
197→	}
198→	cmd := exec.Command("tmux", "kill-session", "-t", s.name)
199→	out, err := cmd.CombinedOutput()
200→	if err != nil {
201→		return fmt.Errorf("tmux kill-session: %w\n%s", err, out)
202→	}
203→	return nil
204→}
205→
206→// shellQuote wraps s in single quotes with proper escaping for POSIX shells.
207→func shellQuote(s string) string {
208→	return "'" + strings.ReplaceAll(s, "'", "'\\''") + "'"
209→}
