139→// runOutput executes an `entire` subcommand and returns (output, error).
140→func runOutput(dir string, args ...string) (string, error) {
141→	cmd := exec.Command(BinPath(), args...)
142→	cmd.Dir = dir
143→	cmd.Env = append(os.Environ(), "ENTIRE_TEST_TTY=0")
144→
145→	out, err := cmd.CombinedOutput()
146→	if err != nil {
147→		return string(out), &ExecError{
148→			Args:   args,
149→			Err:    err,
150→			Output: string(out),
151→		}
152→	}
153→	return strings.TrimSpace(string(out)), nil
