143→func configureDroidRepoSettings(repoDir string) error {
144→	home, err := os.UserHomeDir()
145→	if err != nil {
146→		return fmt.Errorf("get home dir: %w", err)
147→	}
148→
149→	globalSettingsPath := filepath.Join(home, ".factory", "settings.json")
150→	repoSettingsPath := filepath.Join(repoDir, droidRepoSettingsPath)
151→
152→	if err := mergeDroidCustomModels(globalSettingsPath, repoSettingsPath); err != nil {
153→		return err
154→	}
155→	if err := ensureGitInfoExcludeContains(repoDir, droidRepoSettingsPath); err != nil {
156→		return fmt.Errorf("exclude droid settings from git: %w", err)
157→	}
158→	return nil
