328→// runScenario runs the test function and recovers from errScenarioRestart
329→// panics triggered by transient API errors in RunPrompt. Returns true if
330→// the scenario should be restarted with a fresh repository.
331→func runScenario(t *testing.T, s *RepoState, ctx context.Context, fn func(t *testing.T, s *RepoState, ctx context.Context)) (restarted bool) {
332→	t.Helper()
333→	defer func() {
334→		if r := recover(); r != nil {
335→			if _, ok := r.(errScenarioRestart); ok {
336→				restarted = true
337→				return
338→			}
339→			panic(r) // re-panic for unexpected panics
340→		}
341→	}()
342→	fn(t, s, ctx)
343→	return false
344→}
345→
346→const maxScenarioRestarts = 2 // restart up to 2 times = 3 total attempts
347→
348→// errScenarioRestart is panicked by RunPrompt when a transient API error is
349→// detected. ForEachAgent recovers from this panic and restarts the test
350→// scenario with a fresh repository, avoiding stale CLI state from the failed
351→// attempt.
352→type errScenarioRestart struct {
353→	msg string
354→}
355→
356→// RunPrompt runs an agent prompt, logs the command and output to ConsoleLog,
357→// and returns the result. If the agent reports a transient API error, it
358→// panics with errScenarioRestart to trigger a full scenario restart in
359→// ForEachAgent (see runScenario).
360→func (s *RepoState) RunPrompt(t *testing.T, ctx context.Context, prompt string, opts ...agents.Option) (agents.Output, error) {
361→	t.Helper()
362→	out, err := s.Agent.RunPrompt(ctx, s.Dir, prompt, opts...)
363→	s.logPromptResult(out)
364→
365→	if err != nil && s.Agent.IsTransientError(out, err) {
366→		errMsg := fmt.Sprintf("transient API error (stderr: %s)", strings.TrimSpace(out.Stderr))
367→		t.Logf("%s — restarting scenario", errMsg)
368→		fmt.Fprintf(s.ConsoleLog, "> [transient] %s — restarting scenario\n", errMsg)
369→		panic(errScenarioRestart{msg: errMsg})
370→	}
371→
372→	return out, err
373→}
