	deadline := time.Now().Add(timeout)
	for {
		matches, err := filepath.Glob(pattern)
		require.NoError(t, err)
		if len(matches) > 0 {
			return
		}
		if time.Now().After(deadline) {
			t.Fatalf("expected files matching %s in %s within %s", glob, dir, timeout)
		}
