  1→package entire
  2→
  3→import (
  4→	"encoding/json"
  5→	"log"
  6→	"os"
  7→	"os/exec"
  8→	"strings"
  9→	"testing"
 10→)
 11→
 12→// BinPath returns the path to the entire binary from E2E_ENTIRE_BIN.
 13→// The mise test:e2e tasks set this automatically via `mise run build`.
 14→func BinPath() string {
 15→	p := os.Getenv("E2E_ENTIRE_BIN")
 16→	if p == "" {
 17→		log.Fatal("entire: E2E_ENTIRE_BIN not set — run tests via `mise run test:e2e`")
 18→	}
 19→	return p
 20→}
 21→
 22→// RewindPoint represents a single entry from `entire rewind --list`.
 23→type RewindPoint struct {
 24→	ID             string `json:"id"`
 25→	Message        string `json:"message"`
 26→	MetadataDir    string `json:"metadata_dir"`
 27→	Date           string `json:"date"`
 28→	IsLogsOnly     bool   `json:"is_logs_only"`
 29→	CondensationID string `json:"condensation_id"`
 30→	SessionID      string `json:"session_id"`
 31→}
 32→
 33→// Enable runs `entire enable` for the given agent with telemetry disabled.
 34→func Enable(t *testing.T, dir, agent string) {
 35→	t.Helper()
 36→	run(t, dir, "enable", "--agent", agent, "--telemetry=false")
 37→}
 38→
 39→// Disable runs `entire disable` in the given directory.
 40→func Disable(t *testing.T, dir string) {
 41→	t.Helper()
 42→	run(t, dir, "disable")
 43→}
 44→
 45→// RewindList runs `entire rewind --list` and parses the JSON output.
 46→func RewindList(t *testing.T, dir string) []RewindPoint {
 47→	t.Helper()
 48→	out := run(t, dir, "rewind", "--list")
 49→
 50→	var points []RewindPoint
 51→	if err := json.Unmarshal([]byte(out), &points); err != nil {
 52→		t.Fatalf("parse rewind list: %v\nraw output: %s", err, out)
 53→	}
 54→	return points
 55→}
 56→
 57→// Rewind runs `entire rewind --to <id>`. Returns an error instead of
 58→// failing the test, since callers may test failure cases.
 59→func Rewind(t *testing.T, dir, id string) error {
 60→	t.Helper()
 61→	return runErr(dir, "rewind", "--to", id)
 62→}
 63→
 64→// RewindLogsOnly runs `entire rewind --to <id> --logs-only`.
 65→func RewindLogsOnly(t *testing.T, dir, id string) error {
 66→	t.Helper()
 67→	return runErr(dir, "rewind", "--to", id, "--logs-only")
 68→}
 69→
 70→// run executes an `entire` subcommand in dir and fails the test on error.
 71→func run(t *testing.T, dir string, args ...string) string {
 72→	t.Helper()
 73→	cmd := exec.Command(BinPath(), args...)
 74→	cmd.Dir = dir
 75→	cmd.Env = append(os.Environ(), "ENTIRE_TEST_TTY=0")
 76→
 77→	out, err := cmd.CombinedOutput()
 78→	if err != nil {
 79→		t.Fatalf("entire %s failed: %v\n%s", strings.Join(args, " "), err, out)
 80→	}
 81→	return strings.TrimSpace(string(out))
 82→}
 83→
 84→// runErr executes an `entire` subcommand in dir and returns any error.
 85→func runErr(dir string, args ...string) error {
 86→	cmd := exec.Command(BinPath(), args...)
 87→	cmd.Dir = dir
 88→	cmd.Env = append(os.Environ(), "ENTIRE_TEST_TTY=0")
 89→
 90→	out, err := cmd.CombinedOutput()
 91→	if err != nil {
 92→		return &ExecError{
 93→			Args:   args,
 94→			Err:    err,
 95→			Output: string(out),
 96→		}
 97→	}
 98→	return nil
 99→}
100→
101→// ExecError wraps an entire CLI execution failure with its output.
102→type ExecError struct {
103→	Args   []string
104→	Err    error
105→	Output string
106→}
107→
108→func (e *ExecError) Error() string {
109→	return "entire " + strings.Join(e.Args, " ") + ": " + e.Err.Error() + "\n" + e.Output
110→}
111→
112→func (e *ExecError) Unwrap() error {
113→	return e.Err
114→}
115→
116→// Explain runs `entire explain --checkpoint <id>` and returns the output.
117→func Explain(t *testing.T, dir, checkpointID string) string {
118→	t.Helper()
119→	return run(t, dir, "explain", "--checkpoint", checkpointID)
120→}
121→
122→// ExplainGenerate runs `entire explain --checkpoint <id> --generate`.
123→// Returns (output, error) — doesn't fail test since callers may test failure cases.
124→func ExplainGenerate(dir, checkpointID string) (string, error) {
125→	return runOutput(dir, "explain", "--checkpoint", checkpointID, "--generate")
126→}
127→
128→// ExplainCommit runs `entire explain --commit <ref>`.
129→// Returns (output, error) — for testing failure cases.
130→func ExplainCommit(dir, ref string) (string, error) {
131→	return runOutput(dir, "explain", "--commit", ref)
132→}
133→
134→// Resume runs `entire resume <branch> --force` and returns the output.
135→func Resume(dir, branch string) (string, error) {
136→	return runOutput(dir, "resume", branch, "--force")
137→}
138→
139→// runOutput executes an `entire` subcommand and returns (output, error).
140→func runOutput(dir string, args ...string) (string, error) {
141→	cmd := exec.Command(BinPath(), args...)
142→	cmd.Dir = dir
143→	cmd.Env = append(os.Environ(), "ENTIRE_TEST_TTY=0")
144→
145→	out, err := cmd.CombinedOutput()
