package entire

import (
	"encoding/json"
	"log"
	"os"
	"os/exec"
	"strings"
	"testing"
)

// BinPath returns the path to the entire binary from E2E_ENTIRE_BIN.
// The mise test:e2e tasks set this automatically via `mise run build`.
func BinPath() string {
	p := os.Getenv("E2E_ENTIRE_BIN")
	if p == "" {
		log.Fatal("entire: E2E_ENTIRE_BIN not set — run tests via `mise run test:e2e`")
	}
	return p
}

// RewindPoint represents a single entry from `entire rewind --list`.
type RewindPoint struct {
	ID             string `json:"id"`
	Message        string `json:"message"`
	MetadataDir    string `json:"metadata_dir"`
	Date           string `json:"date"`
	IsLogsOnly     bool   `json:"is_logs_only"`
	CondensationID string `json:"condensation_id"`
	SessionID      string `json:"session_id"`
}

// Enable runs `entire enable` for the given agent with telemetry disabled.
func Enable(t *testing.T, dir, agent string) {
	t.Helper()
	run(t, dir, "enable", "--agent", agent, "--telemetry=false")
}

// Disable runs `entire disable` in the given directory.
func Disable(t *testing.T, dir string) {
	t.Helper()
	run(t, dir, "disable")
}

// RewindList runs `entire rewind --list` and parses the JSON output.
func RewindList(t *testing.T, dir string) []RewindPoint {
	t.Helper()
	out := run(t, dir, "rewind", "--list")

	var points []RewindPoint
	if err := json.Unmarshal([]byte(out), &points); err != nil {
		t.Fatalf("parse rewind list: %v\nraw output: %s", err, out)
	}
	return points
}

// Rewind runs `entire rewind --to <id>`. Returns an error instead of
// failing the test, since callers may test failure cases.
func Rewind(t *testing.T, dir, id string) error {
	t.Helper()
	return runErr(dir, "rewind", "--to", id)
}

// RewindLogsOnly runs `entire rewind --to <id> --logs-only`.
func RewindLogsOnly(t *testing.T, dir, id string) error {
	t.Helper()
	return runErr(dir, "rewind", "--to", id, "--logs-only")
}

// run executes an `entire` subcommand in dir and fails the test on error.
func run(t *testing.T, dir string, args ...string) string {
	t.Helper()
	cmd := exec.Command(BinPath(), args...)
	cmd.Dir = dir
	cmd.Env = append(os.Environ(), "ENTIRE_TEST_TTY=0")

	out, err := cmd.CombinedOutput()
	if err != nil {
		t.Fatalf("entire %s failed: %v\n%s", strings.Join(args, " "), err, out)
	}
	return strings.TrimSpace(string(out))
}

// runErr executes an `entire` subcommand in dir and returns any error.
func runErr(dir string, args ...string) error {
	cmd := exec.Command(BinPath(), args...)
	cmd.Dir = dir
	cmd.Env = append(os.Environ(), "ENTIRE_TEST_TTY=0")

	out, err := cmd.CombinedOutput()
	if err != nil {
		return &ExecError{
			Args:   args,
			Err:    err,
			Output: string(out),
		}
	}
	return nil
}

// ExecError wraps an entire CLI execution failure with its output.
type ExecError struct {
	Args   []string
	Err    error
	Output string
}

func (e *ExecError) Error() string {
	return "entire " + strings.Join(e.Args, " ") + ": " + e.Err.Error() + "\n" + e.Output
}

func (e *ExecError) Unwrap() error {
	return e.Err
}

// Explain runs `entire explain --checkpoint <id>` and returns the output.
func Explain(t *testing.T, dir, checkpointID string) string {
	t.Helper()
	return run(t, dir, "explain", "--checkpoint", checkpointID)
}

// ExplainGenerate runs `entire explain --checkpoint <id> --generate`.
// Returns (output, error) — doesn't fail test since callers may test failure cases.
func ExplainGenerate(dir, checkpointID string) (string, error) {
	return runOutput(dir, "explain", "--checkpoint", checkpointID, "--generate")
}

// ExplainCommit runs `entire explain --commit <ref>`.
// Returns (output, error) — for testing failure cases.
func ExplainCommit(dir, ref string) (string, error) {
	return runOutput(dir, "explain", "--commit", ref)
}

// Resume runs `entire resume <branch> --force` and returns the output.
func Resume(dir, branch string) (string, error) {
	return runOutput(dir, "resume", branch, "--force")
}

// runOutput executes an `entire` subcommand and returns (output, error).
func runOutput(dir string, args ...string) (string, error) {
	cmd := exec.Command(BinPath(), args...)
	cmd.Dir = dir
	cmd.Env = append(os.Environ(), "ENTIRE_TEST_TTY=0")

	out, err := cmd.CombinedOutput()
	if err != nil {
		return string(out), &ExecError{
			Args:   args,
			Err:    err,
			Output: string(out),
		}
	}
	return strings.TrimSpace(string(out)), nil
}

package testutil

import (
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"regexp"
	"strconv"
	"strings"
	"testing"
	"time"
)

// ArtifactRoot is the absolute path to the artifact output directory.
// Must be set in TestMain before any tests run.
var ArtifactRoot string

// ArtifactTimestamp is the timestamp subdirectory for this test run.
var ArtifactTimestamp = time.Now().Format("2006-01-02T15-04-05")

var runDirOverride string

// SetRunDir overrides the artifact run directory (e.g. from E2E_ARTIFACT_DIR).
func SetRunDir(dir string) {
	runDirOverride = dir
}

// ArtifactRunDir returns the directory for the current test run.
func ArtifactRunDir() string {
	if runDirOverride != "" {
		return runDirOverride
	}
	return filepath.Join(ArtifactRoot, ArtifactTimestamp)
}

func artifactDir(t *testing.T) string {
	t.Helper()
	name := strings.ReplaceAll(t.Name(), "/", "-")
	dir := filepath.Join(ArtifactRunDir(), name)
	if err := os.MkdirAll(dir, 0o755); err != nil {
		t.Logf("warning: failed to create artifact dir: %v", err)
	}
	return dir
}

// CaptureArtifacts captures git state, checkpoint metadata, entire logs,
// and console output to the artifact directory.
func CaptureArtifacts(t *testing.T, s *RepoState) {
	t.Helper()
	dir := s.ArtifactDir

	writeArtifact(t, dir, "git-log.txt",
		gitOutputSafe(s.Dir, "log", "--decorate", "--graph", "--all"))

	writeArtifact(t, dir, "git-tree.txt",
		gitOutputSafe(s.Dir, "ls-tree", "-r", "HEAD")+
			"\n--- entire/checkpoints/v1 ---\n"+
			gitOutputSafe(s.Dir, "ls-tree", "-r", "entire/checkpoints/v1"))

	// console.log is written incrementally to disk via s.ConsoleLog (*os.File),
	// so it already exists in the artifact dir and survives global timeouts.

	// Capture final pane content from interactive sessions, then close.
	// Must happen here (not in a separate t.Cleanup) because cleanup
	// functions run LIFO — closing first would kill the tmux session
	// before we can capture.
	if s.session != nil {
		pane := s.session.Capture()
		writeArtifact(t, dir, "pane.txt", pane)
		_ = s.session.Close()
	}

	if t.Failed() {
		writeArtifact(t, dir, "FAIL", "")
	} else {
		writeArtifact(t, dir, "PASS", "")
	}

	captureCheckpointMetadata(t, s, dir)
	captureEntireLogs(t, s.Dir, dir)

	if os.Getenv("E2E_KEEP_REPOS") != "" {
		link := filepath.Join(dir, "repo")
		if err := os.Symlink(s.Dir, link); err != nil {
			t.Logf("warning: failed to symlink repo: %v", err)
		}
	}
}

func captureCheckpointMetadata(t *testing.T, s *RepoState, outDir string) {
	t.Helper()
	commits := NewCheckpointCommits(t, s)
	metaDir := filepath.Join(outDir, "checkpoint-metadata")

	cpIDRe := regexp.MustCompile(`(?m)^Checkpoint:\s+(\S+)`)
	for _, sha := range commits {
		msg := gitOutputSafe(s.Dir, "log", "-1", "--format=%B", sha)
		m := cpIDRe.FindStringSubmatch(msg)
		if m == nil || len(m[1]) < 3 {
			continue
		}
		id := m[1]
		cpPath := CheckpointPath(id)

		cpDir := filepath.Join(metaDir, cpPath)
		_ = os.MkdirAll(cpDir, 0o755)
		raw := gitOutputSafe(s.Dir, "show", sha+":"+cpPath+"/metadata.json")
		writeArtifact(t, cpDir, "metadata.json", raw)

		for i := 0; ; i++ {
			sessPath := fmt.Sprintf("%s/%d/metadata.json", cpPath, i)
			raw := gitOutputSafe(s.Dir, "show", sha+":"+sessPath)
			if raw == "" {
				break
			}
			sessDir := filepath.Join(cpDir, strconv.Itoa(i))
			_ = os.MkdirAll(sessDir, 0o755)
			writeArtifact(t, sessDir, "metadata.json", raw)
		}
	}
}

func captureEntireLogs(t *testing.T, repoDir, outDir string) {
	t.Helper()
	logDir := filepath.Join(repoDir, ".entire", "logs")
	entries, err := os.ReadDir(logDir)
	if err != nil {
		return
	}
	dst := filepath.Join(outDir, "entire-logs")
	_ = os.MkdirAll(dst, 0o755)
	for _, e := range entries {
		data, err := os.ReadFile(filepath.Join(logDir, e.Name()))
		if err != nil {
			continue
		}
		writeArtifact(t, dst, e.Name(), string(data))
	}
}

func writeArtifact(t *testing.T, dir, name, content string) {
	t.Helper()
	path := filepath.Join(dir, name)
	if err := os.WriteFile(path, []byte(content), 0o644); err != nil {
		t.Logf("warning: failed to write artifact %s: %v", path, err)
	}
}

func gitOutputSafe(dir string, args ...string) string {
	cmd := exec.Command("git", args...)
	cmd.Dir = dir
	out, err := cmd.Output()
	if err != nil {
		return ""
	}
	return string(out)
}

