 33→// SetupRepo creates a fresh git repository in a temporary directory, seeds it
 34→// with an initial commit, and runs `entire enable` for the given agent.
 35→// Artifact capture is registered as a cleanup function.
 36→//
 37→// When E2E_KEEP_REPOS is set, the temporary directory is not cleaned up
 38→// so it can be inspected after the test. A symlink in the artifact dir
 39→// points to the preserved repo.
 40→func SetupRepo(t *testing.T, agent agents.Agent) *RepoState {
 41→	t.Helper()
 42→
 43→	keepRepos := os.Getenv("E2E_KEEP_REPOS") != ""
 44→
 45→	// Always use os.MkdirTemp instead of t.TempDir(). Go's t.TempDir()
 46→	// creates nested subdirectories (TestName.../001/) whose structure
 47→	// confuses some agents' (e.g. opencode) working-directory resolution.
 48→	dir, err := os.MkdirTemp("", "e2e-repo-*")
 49→	if err != nil {
 50→		t.Fatalf("create temp dir: %v", err)
 51→	}
 52→	if keepRepos {
 53→		t.Logf("E2E_KEEP_REPOS: repo will be preserved at %s", dir)
 54→	} else {
 55→		t.Cleanup(func() { os.RemoveAll(dir) })
 56→	}
 57→
 58→	// Resolve symlinks (macOS: /var -> /private/var) so paths match
 59→	// what agent CLIs see when they resolve their own CWD.
 60→	if resolved, err := filepath.EvalSymlinks(dir); err == nil {
 61→		dir = resolved
 62→	}
 63→
 64→	Git(t, dir, "init")
 65→	Git(t, dir, "config", "user.name", "E2E Test")
 66→	Git(t, dir, "config", "user.email", "e2e@test.local")
 67→	Git(t, dir, "commit", "--allow-empty", "-m", "initial commit")
 68→
 69→	// External agents need external_agents enabled in settings before enable,
 70→	// so the CLI can discover the agent binary via PATH during DiscoverAndRegister.
 71→	if ea, ok := agent.(agents.ExternalAgent); ok && ea.IsExternalAgent() {
 72→		entireDir := filepath.Join(dir, ".entire")
 73→		if err := os.MkdirAll(entireDir, 0o755); err != nil {
 74→			t.Fatalf("create .entire for external agent: %v", err)
 75→		}
 76→		if err := os.WriteFile(filepath.Join(entireDir, "settings.json"),
 77→			[]byte("{\"external_agents\": true}\n"), 0o644); err != nil {
 78→			t.Fatalf("write external_agents setting: %v", err)
 79→		}
 80→	}
 81→
 82→	entire.Enable(t, dir, agent.EntireAgent())
 83→	if agent.Name() == "factoryai-droid" {
 84→		if err := configureDroidRepoSettings(dir); err != nil {
 85→			t.Fatalf("configure droid repo settings: %v", err)
 86→		}
 87→	}
 88→	PatchSettings(t, dir, map[string]any{"log_level": "debug"})
 89→
 90→	// Copilot CLI blocks on a "No copilot instructions found" notice in fresh
 91→	// repos that lack .github/copilot-instructions.md, preventing the interactive
 92→	// prompt from appearing.
 93→	if agent.Name() == "copilot-cli" {
 94→		ghDir := filepath.Join(dir, ".github")
 95→		if err := os.MkdirAll(ghDir, 0o755); err != nil {
 96→			t.Fatalf("create .github dir: %v", err)
 97→		}
 98→		if err := os.WriteFile(filepath.Join(ghDir, "copilot-instructions.md"), []byte("# E2E Test\n"), 0o644); err != nil {
 99→			t.Fatalf("write copilot-instructions.md: %v", err)
100→		}
101→	}
102→
103→	// OpenCode's non-interactive mode auto-rejects external_directory permission
104→	// since there's no user to prompt. Write a config to allow it.
105→	if agent.Name() == "opencode" {
106→		cfg := `{"$schema": "https://opencode.ai/config.json", "permission": {"external_directory": "allow"}}`
107→		if key := os.Getenv("ANTHROPIC_API_KEY"); key != "" {
108→			cfg = fmt.Sprintf(`{"$schema": "https://opencode.ai/config.json", "permission": {"external_directory": "allow"}, "provider": {"anthropic": {"options": {"apiKey": %q}}}}`, key)
109→		}
110→		if err := os.WriteFile(filepath.Join(dir, "opencode.json"), []byte(cfg+"\n"), 0o644); err != nil {
111→			t.Fatalf("write opencode.json: %v", err)
112→		}
113→	}
114→
115→	// Create artifact dir eagerly so console.log is written to disk
116→	// incrementally. Even if the test is killed by a global timeout,
117→	// partial output survives.
118→	artDir := artifactDir(t)
119→	consoleLog, err := os.Create(filepath.Join(artDir, "console.log"))
120→	if err != nil {
121→		t.Fatalf("create console.log: %v", err)
122→	}
123→
124→	state := &RepoState{
125→		Agent:            agent,
126→		Dir:              dir,
127→		ArtifactDir:      artDir,
128→		HeadBefore:       GitOutput(t, dir, "rev-parse", "HEAD"),
129→		CheckpointBefore: GitOutput(t, dir, "rev-parse", "entire/checkpoints/v1"),
130→		ConsoleLog:       consoleLog,
131→	}
132→
133→	t.Cleanup(func() {
134→		_ = consoleLog.Close()
135→		if !state.skipArtifacts {
136→			CaptureArtifacts(t, state)
137→		}
138→	})
139→
140→	return state
141→}
142→
143→func configureDroidRepoSettings(repoDir string) error {
144→	home, err := os.UserHomeDir()
145→	if err != nil {
146→		return fmt.Errorf("get home dir: %w", err)
147→	}
148→
149→	globalSettingsPath := filepath.Join(home, ".factory", "settings.json")
150→	repoSettingsPath := filepath.Join(repoDir, droidRepoSettingsPath)
151→
152→	if err := mergeDroidCustomModels(globalSettingsPath, repoSettingsPath); err != nil {
153→		return err
154→	}
155→	if err := ensureGitInfoExcludeContains(repoDir, droidRepoSettingsPath); err != nil {
156→		return fmt.Errorf("exclude droid settings from git: %w", err)
157→	}
158→	return nil
159→}
160→
161→func mergeDroidCustomModels(globalSettingsPath, repoSettingsPath string) error {
162→	globalSettings, err := loadJSONMap(globalSettingsPath, "global droid settings")
163→	if err != nil {
164→		return err
165→	}
166→
167→	customModels, ok := globalSettings["customModels"]
168→	if !ok {
169→		return fmt.Errorf(
170→			"global droid settings at %s missing customModels; repo-local %s shadows global settings",
171→			globalSettingsPath,
172→			repoSettingsPath,
173→		)
174→	}
175→
176→	var models []json.RawMessage
177→	if err := json.Unmarshal(customModels, &models); err != nil {
178→		return fmt.Errorf("parse customModels in %s: %w", globalSettingsPath, err)
179→	}
180→	if len(models) == 0 {
181→		return fmt.Errorf("global droid settings at %s has empty customModels", globalSettingsPath)
182→	}
183→
184→	repoSettings, err := loadJSONMap(repoSettingsPath, "repo-local droid settings")
185→	if err != nil {
186→		return err
187→	}
188→	repoSettings["customModels"] = customModels
189→
190→	// Set the active custom model so interactive mode uses the BYOK model
191→	// instead of prompting for selection. The value must match the Model
192→	// field from the customModels entry (not the displayName).
193→	modelJSON, err := json.Marshal(agents.DefaultDroidModel())
194→	if err != nil {
195→		return fmt.Errorf("marshal model setting: %w", err)
196→	}
197→	repoSettings["model"] = json.RawMessage(modelJSON)
198→
199→	// High autonomy prevents Droid from asking for confirmation during
200→	// interactive E2E tests, which would cause hangs waiting for input.
201→	repoSettings["autonomyMode"] = json.RawMessage(`"auto-high"`)
202→	repoSettings["completionSound"] = json.RawMessage(`"off"`)
203→
204→	out, err := json.MarshalIndent(repoSettings, "", "  ")
205→	if err != nil {
206→		return fmt.Errorf("marshal repo-local droid settings: %w", err)
207→	}
208→	out = append(out, '\n')
209→
210→	if err := os.WriteFile(repoSettingsPath, out, 0o600); err != nil {
211→		return fmt.Errorf("write repo-local droid settings %s: %w", repoSettingsPath, err)
212→	}
213→	return nil
214→}
215→
216→func loadJSONMap(path, description string) (map[string]json.RawMessage, error) {
217→	data, err := os.ReadFile(path)
218→	if err != nil {
219→		return nil, fmt.Errorf("read %s at %s: %w", description, path, err)
220→	}
221→
222→	var parsed map[string]json.RawMessage
223→	if err := json.Unmarshal(data, &parsed); err != nil {
224→		return nil, fmt.Errorf("parse %s at %s: %w", description, path, err)
225→	}
226→	if parsed == nil {
227→		parsed = make(map[string]json.RawMessage)
228→	}
229→	return parsed, nil
230→}
231→
232→func ensureGitInfoExcludeContains(repoDir, entry string) error {
233→	excludePath := filepath.Join(repoDir, ".git", "info", "exclude")
234→
235→	data, err := os.ReadFile(excludePath)
236→	if err != nil && !errors.Is(err, os.ErrNotExist) {
237→		return fmt.Errorf("read %s: %w", excludePath, err)
238→	}
239→
240→	normalized := strings.ReplaceAll(string(data), "\r\n", "\n")
241→	for _, line := range strings.Split(normalized, "\n") {
242→		if strings.TrimSpace(line) == entry {
243→			return nil
244→		}
245→	}
246→
247→	var b strings.Builder
248→	if len(data) > 0 {
249→		b.Write(data)
250→		if data[len(data)-1] != '\n' {
251→			b.WriteByte('\n')
252→		}
253→	}
254→	b.WriteString(entry)
255→	b.WriteByte('\n')
256→
257→	if err := os.MkdirAll(filepath.Dir(excludePath), 0o755); err != nil {
258→		return fmt.Errorf("create %s: %w", filepath.Dir(excludePath), err)
259→	}
260→	if err := os.WriteFile(excludePath, []byte(b.String()), 0o644); err != nil {
261→		return fmt.Errorf("write %s: %w", excludePath, err)
262→	}
263→	return nil
264→}
265→
266→// ForEachAgent runs fn as a parallel subtest for every registered agent.
267→// It handles repo setup, concurrency gating, context timeout, and cleanup.
268→// The timeout is scaled by each agent's TimeoutMultiplier.
269→//
270→// If RunPrompt detects a transient API error (e.g. rate limit, token refresh
271→// failure), it panics with errScenarioRestart. ForEachAgent recovers from the
272→// panic and restarts the entire scenario with a fresh repository, up to
273→// maxScenarioRestarts times. This avoids stale CLI session state from the
274→// failed attempt poisoning the retry.
275→func ForEachAgent(t *testing.T, timeout time.Duration, fn func(t *testing.T, s *RepoState, ctx context.Context)) {
276→	t.Helper()
277→	t.Parallel()
278→	all := agents.All()
279→	if len(all) == 0 {
280→		t.Skip("no agents registered (check E2E_AGENT filter)")
281→	}
282→	for _, agent := range all {
283→		t.Run(agent.Name(), func(t *testing.T) {
284→			// Use the global test deadline for slot wait so we don't
285→			// skip prematurely — only bail if the whole binary is dying.
286→			slotCtx := context.Background()
287→			if deadline, ok := t.Deadline(); ok {
288→				var cancel context.CancelFunc
289→				slotCtx, cancel = context.WithDeadline(slotCtx, deadline)
290→				defer cancel()
291→			}
292→			if err := agents.AcquireSlot(slotCtx, agent); err != nil {
293→				t.Fatalf("timed out waiting for agent slot: %v", err)
294→			}
295→			defer agents.ReleaseSlot(agent)
296→
297→			// Per-test timeout starts after slot is acquired, scaled
298→			// by the agent's multiplier (e.g. 2.5× for gemini).
299→			scaled := time.Duration(float64(timeout) * agent.TimeoutMultiplier())
300→
301→			var prevState *RepoState
302→			for attempt := range maxScenarioRestarts + 1 {
303→				s := SetupRepo(t, agent)
304→				ctx, cancel := context.WithTimeout(context.Background(), scaled)
305→
306→				// On restart, suppress artifact capture from the previous
307→				// failed attempt so it doesn't overwrite the final one.
308→				if prevState != nil {
309→					prevState.skipArtifacts = true
310→				}
311→
312→				restarted := runScenario(t, s, ctx, fn)
313→				cancel()
314→
315→				if !restarted {
316→					return
317→				}
318→				prevState = s
319→				if attempt >= maxScenarioRestarts {
320→					t.Fatalf("exhausted %d scenario attempts due to transient API errors", maxScenarioRestarts+1)
321→				}
322→				t.Logf("transient error, restarting scenario (attempt %d/%d)", attempt+2, maxScenarioRestarts+1)
323→			}
324→		})
325→	}
326→}
327→
328→// runScenario runs the test function and recovers from errScenarioRestart
329→// panics triggered by transient API errors in RunPrompt. Returns true if
330→// the scenario should be restarted with a fresh repository.
331→func runScenario(t *testing.T, s *RepoState, ctx context.Context, fn func(t *testing.T, s *RepoState, ctx context.Context)) (restarted bool) {
332→	t.Helper()
333→	defer func() {
334→		if r := recover(); r != nil {
335→			if _, ok := r.(errScenarioRestart); ok {
336→				restarted = true
337→				return
338→			}
339→			panic(r) // re-panic for unexpected panics
340→		}
341→	}()
342→	fn(t, s, ctx)
343→	return false
344→}
345→
346→const maxScenarioRestarts = 2 // restart up to 2 times = 3 total attempts
347→
348→// errScenarioRestart is panicked by RunPrompt when a transient API error is
349→// detected. ForEachAgent recovers from this panic and restarts the test
350→// scenario with a fresh repository, avoiding stale CLI state from the failed
351→// attempt.
352→type errScenarioRestart struct {
353→	msg string
354→}
355→
356→// RunPrompt runs an agent prompt, logs the command and output to ConsoleLog,
357→// and returns the result. If the agent reports a transient API error, it
358→// panics with errScenarioRestart to trigger a full scenario restart in
359→// ForEachAgent (see runScenario).
360→func (s *RepoState) RunPrompt(t *testing.T, ctx context.Context, prompt string, opts ...agents.Option) (agents.Output, error) {
361→	t.Helper()
362→	out, err := s.Agent.RunPrompt(ctx, s.Dir, prompt, opts...)
363→	s.logPromptResult(out)
364→
365→	if err != nil && s.Agent.IsTransientError(out, err) {
366→		errMsg := fmt.Sprintf("transient API error (stderr: %s)", strings.TrimSpace(out.Stderr))
367→		t.Logf("%s — restarting scenario", errMsg)
368→		fmt.Fprintf(s.ConsoleLog, "> [transient] %s — restarting scenario\n", errMsg)
369→		panic(errScenarioRestart{msg: errMsg})
370→	}
371→
372→	return out, err
373→}
374→
375→func (s *RepoState) logPromptResult(out agents.Output) {
376→	s.ConsoleLog.WriteString("> " + out.Command + "\n")
377→	s.ConsoleLog.WriteString("stdout:\n" + out.Stdout + "\n")
378→	s.ConsoleLog.WriteString("stderr:\n" + out.Stderr + "\n")
379→}
