  3→import (
  4→	"context"
  5→	"errors"
  6→	"fmt"
  7→	"os"
  8→	"os/exec"
  9→	"path/filepath"
 10→	"strings"
 11→	"syscall"
 12→	"time"
 13→)
 14→
 15→// cleanConfigDir creates an isolated temp directory for CLAUDE_CONFIG_DIR so
 16→// that E2E test runs don't inherit any user settings (CLAUDE.md, skills,
 17→// projects, plugins, etc.).
 18→//
 19→// On CI, it symlinks .claude.json (which Bootstrap() wrote with the API key
 20→// and hasCompletedOnboarding). Locally, it writes a minimal .claude.json to
 21→// skip the onboarding flow — Keychain-based auth works without any other files.
 22→func cleanConfigDir() (string, error) {
 23→	dst, err := os.MkdirTemp("", "claude-config-*")
 24→	if err != nil {
 25→		return "", err
 26→	}
 27→
 28→	if os.Getenv("CI") != "" {
 29→		if home, err := os.UserHomeDir(); err == nil {
 30→			src := filepath.Join(home, ".claude", ".claude.json")
 31→			if _, err := os.Stat(src); err == nil {
 32→				_ = os.Symlink(src, filepath.Join(dst, ".claude.json"))
 33→			}
 34→		}
 35→	} else {
 36→		_ = os.WriteFile(filepath.Join(dst, ".claude.json"),
 37→			[]byte(`{"hasCompletedOnboarding":true}`), 0o644)
 38→	}
 39→
 40→	return dst, nil
 41→}
 42→
 43→// cleanEnv returns os.Environ() with agent-incompatible variables removed.
 44→// It strips CLAUDECODE (so Claude Code doesn't refuse to start inside this
 45→// test runner) and ENTIRE_TEST_TTY (so agents exercise the real TTY detection
 46→// paths instead of the test override).
 47→func cleanEnv() []string {
 48→	var env []string
 49→	for _, e := range os.Environ() {
 50→		if strings.HasPrefix(e, "CLAUDECODE=") || strings.HasPrefix(e, "ENTIRE_TEST_TTY=") {
 51→			continue
 52→		}
 53→		env = append(env, e)
 54→	}
 55→	return env
 56→}
 57→
 58→func init() {
 59→	if env := os.Getenv("E2E_AGENT"); env != "" && env != "claude-code" {
 60→		return
 61→	}
 62→	Register(&Claude{})
 63→}
 64→
 65→type Claude struct{}
 66→
 67→func (c *Claude) Name() string               { return "claude-code" }
 68→func (c *Claude) Binary() string             { return "claude" }
 69→func (c *Claude) EntireAgent() string        { return "claude-code" }
 70→func (c *Claude) PromptPattern() string      { return `❯` }
 71→func (c *Claude) TimeoutMultiplier() float64 { return 1.0 }
 72→
 73→func (c *Claude) IsTransientError(out Output, _ error) bool {
 74→	transientPatterns := []string{
 75→		"overloaded",
 76→		"rate limit",
 77→		"529",
 78→		"503",
 79→		"ECONNRESET",
 80→		"ETIMEDOUT",
 81→	}
 82→	for _, p := range transientPatterns {
 83→		if strings.Contains(out.Stderr, p) {
 84→			return true
 85→		}
 86→	}
 87→	return false
 88→}
 89→
 90→func (c *Claude) Bootstrap() error {
 91→	// On CI, write a config file so Claude Code uses the API key from the
 92→	// environment instead of trying OAuth/Keychain.
 93→	if os.Getenv("CI") == "" {
 94→		return nil
 95→	}
 96→	apiKey := os.Getenv("ANTHROPIC_API_KEY")
 97→	if apiKey == "" {
 98→		return nil
 99→	}
100→	home, err := os.UserHomeDir()
101→	if err != nil {
102→		return fmt.Errorf("get home dir: %w", err)
103→	}
104→	dir := filepath.Join(home, ".claude")
105→	if err := os.MkdirAll(dir, 0o755); err != nil {
106→		return fmt.Errorf("mkdir %s: %w", dir, err)
107→	}
108→	config := fmt.Sprintf(`{"primaryApiKey":%q,"hasCompletedOnboarding":true}`, apiKey)
