 11→// Output holds the result of running an agent prompt.
 12→type Output struct {
 13→	Command  string
 14→	Stdout   string
 15→	Stderr   string
 16→	ExitCode int
 17→}
 18→
 19→// Option configures how an agent prompt is executed.
 20→type Option func(*runConfig)
 21→type runConfig struct {
 22→	Model          string
 23→	PermissionMode string
 24→	PromptTimeout  time.Duration
 25→}
 26→
 27→// WithModel sets the model to use for the prompt.
 28→func WithModel(model string) Option {
 29→	return func(c *runConfig) { c.Model = model }
 30→}
 31→
 32→// WithPermissionMode sets the permission mode for the prompt.
 33→func WithPermissionMode(mode string) Option {
 34→	return func(c *runConfig) { c.PermissionMode = mode }
 35→}
 36→
 37→// WithPromptTimeout sets a custom timeout for the prompt execution.
 38→func WithPromptTimeout(d time.Duration) Option {
 39→	return func(c *runConfig) { c.PromptTimeout = d }
 40→}
 41→
 42→// Agent defines the interface for an AI coding agent that can be tested.
 43→type Agent interface {
 44→	Name() string
 45→	// Binary returns the CLI binary name (e.g. "kiro-cli-chat").
 46→	Binary() string
 47→	EntireAgent() string
 48→	PromptPattern() string
 49→	// TimeoutMultiplier returns a factor applied to per-test timeouts.
 50→	// Slower agents return values > 1.
 51→	TimeoutMultiplier() float64
 52→	RunPrompt(ctx context.Context, dir string, prompt string, opts ...Option) (Output, error)
 53→	StartSession(ctx context.Context, dir string) (Session, error)
 54→	// Bootstrap performs one-time CI setup (auth config, warmup, etc.).
 55→	// Called before any tests run. Implementations should be idempotent.
 56→	Bootstrap() error
 57→	// IsTransientError returns true if the error from RunPrompt looks like
 58→	// a transient API failure (e.g. 500, rate limit, network error) that
 59→	// is worth retrying.
 60→	IsTransientError(out Output, err error) bool
 61→}
 62→
 63→// Session represents an interactive terminal session with an agent.
 64→type Session interface {
 65→	Send(input string) error
 66→	WaitFor(pattern string, timeout time.Duration) (string, error)
 67→	Capture() string
 68→	Close() error
 69→}
 70→
 71→// ExternalAgent is an optional interface for agents discovered via the
 72→// external agent protocol (entire-agent-* binaries). SetupRepo uses this
 73→// to pre-configure external_agents in settings before running `entire enable`.
 74→type ExternalAgent interface {
 75→	IsExternalAgent() bool
 76→}
 77→
 78→var registry []Agent
 79→var gates = map[string]chan struct{}{}
 80→
 81→// Register adds an agent to the global registry.
 82→func Register(a Agent) {
 83→	registry = append(registry, a)
 84→}
 85→
 86→// RegisterGate sets a concurrency limit for an agent's tests.
 87→// Tests call AcquireSlot/ReleaseSlot to respect this limit.
 88→// The limit can be overridden via E2E_CONCURRENT_TEST_LIMIT.
 89→func RegisterGate(name string, defaultMax int) {
 90→	max := defaultMax
 91→	if v, err := strconv.Atoi(os.Getenv("E2E_CONCURRENT_TEST_LIMIT")); err == nil && v > 0 {
 92→		max = v
 93→	}
 94→	gates[name] = make(chan struct{}, max)
 95→}
 96→
 97→// AcquireSlot blocks until a test slot is available for the agent or the
 98→// context is cancelled. Returns a non-nil error if the context expires
 99→// before a slot opens.
100→func AcquireSlot(ctx context.Context, a Agent) error {
101→	g, ok := gates[a.Name()]
102→	if !ok {
103→		return nil
104→	}
105→	select {
106→	case g <- struct{}{}:
107→		return nil
108→	case <-ctx.Done():
109→		return ctx.Err()
110→	}
111→}
112→
113→// ReleaseSlot frees a test slot for the agent.
114→func ReleaseSlot(a Agent) {
115→	if g, ok := gates[a.Name()]; ok {
116→		<-g
117→	}
118→}
119→
120→// All returns all registered agents.
121→func All() []Agent {
122→	return registry
123→}
124→
125→// filterEnv returns env with entries matching any of the given variable names
126→// removed. Used to strip test-only overrides from agent processes.
127→func filterEnv(env []string, names ...string) []string {
128→	out := make([]string, 0, len(env))
129→	for _, e := range env {
130→		skip := false
131→		for _, name := range names {
132→			if strings.HasPrefix(e, name+"=") {
133→				skip = true
134→				break
135→			}
136→		}
137→		if !skip {
138→			out = append(out, e)
139→		}
140→	}
141→	return out
142→}
