  1→package agents
  2→
  3→import (
  4→	"fmt"
  5→	"os"
  6→	"os/exec"
  7→	"regexp"
  8→	"strings"
  9→	"time"
 10→)
 11→
 12→// TmuxSession implements Session using tmux for PTY-based interactive agents.
 13→type TmuxSession struct {
 14→	name         string
 15→	stableAtSend string   // stable content snapshot when Send was last called
 16→	cleanups     []func() // run on Close
 17→}
 18→
 19→// OnClose registers a function to run when the session is closed.
 20→func (s *TmuxSession) OnClose(fn func()) {
 21→	s.cleanups = append(s.cleanups, fn)
 22→}
 23→
 24→// NewTmuxSession creates a new tmux session running the given command in dir.
 25→// unsetEnv lists environment variable names to strip from the session.
 26→//
 27→// The command is wrapped with `env` to propagate PATH from the current process.
 28→// tmux sessions inherit the tmux server's environment (not the client's), so
 29→// without this, binaries added to PATH by the test runner would not be found.
 30→func NewTmuxSession(name string, dir string, unsetEnv []string, command string, args ...string) (*TmuxSession, error) {
 31→	s := &TmuxSession{name: name}
 32→
 33→	tmuxArgs := []string{"new-session", "-d", "-s", name, "-c", dir}
 34→	var parts []string
 35→	parts = append(parts, "env")
 36→	// Options (-u) must precede variable assignments for BSD env on macOS.
 37→	for _, v := range unsetEnv {
 38→		parts = append(parts, "-u", shellQuote(v))
 39→	}
 40→	parts = append(parts, "PATH="+shellQuote(os.Getenv("PATH")))
 41→	parts = append(parts, shellQuote(command))
 42→	for _, a := range args {
 43→		parts = append(parts, shellQuote(a))
 44→	}
 45→	tmuxArgs = append(tmuxArgs, strings.Join(parts, " "))
 46→
 47→	cmd := exec.Command("tmux", tmuxArgs...)
 48→	if out, err := cmd.CombinedOutput(); err != nil {
 49→		return nil, fmt.Errorf("tmux new-session: %w\n%s", err, out)
 50→	}
 51→	// Keep the pane around after the command exits so we can capture error output.
 52→	setCmd := exec.Command("tmux", "set-option", "-t", name, "remain-on-exit", "on")
 53→	_ = setCmd.Run()
 54→	return s, nil
 55→}
 56→
 57→func (s *TmuxSession) Send(input string) error {
 58→	preSend := stableContent(s.Capture())
 59→	// Send text and Enter separately — some TUIs can swallow Enter
 60→	// if it arrives before the input handler finishes processing the text.
 61→	if err := s.SendKeys(input); err != nil {
 62→		return err
 63→	}
 64→	time.Sleep(200 * time.Millisecond)
 65→	if err := s.SendKeys("Enter"); err != nil {
 66→		return err
 67→	}
 68→
 69→	// Wait for the terminal to reflect the echoed input, then snapshot.
 70→	deadline := time.Now().Add(5 * time.Second)
 71→	for time.Now().Before(deadline) {
 72→		time.Sleep(200 * time.Millisecond)
 73→		current := stableContent(s.Capture())
 74→		if current != preSend {
 75→			s.stableAtSend = current
 76→			return nil
 77→		}
 78→	}
 79→	s.stableAtSend = stableContent(s.Capture())
 80→	return nil
 81→}
 82→
 83→// SendKeys sends raw tmux key names without appending Enter.
 84→func (s *TmuxSession) SendKeys(keys ...string) error {
 85→	args := append([]string{"send-keys", "-t", s.name}, keys...)
 86→	cmd := exec.Command("tmux", args...)
 87→	out, err := cmd.CombinedOutput()
 88→	if err != nil {
 89→		return fmt.Errorf("tmux send-keys: %w\n%s", err, out)
 90→	}
 91→	return nil
 92→}
 93→
 94→const (
 95→	settleTime   = 2 * time.Second
 96→	pollInterval = 500 * time.Millisecond
 97→)
 98→
 99→// stableContent returns the content with the last few lines stripped,
100→// so that TUI status bar updates don't prevent the settle timer.
101→func stableContent(content string) string {
102→	lines := strings.Split(content, "\n")
103→	if len(lines) > 3 {
104→		lines = lines[:len(lines)-3]
105→	}
106→	return strings.Join(lines, "\n")
107→}
108→
109→func (s *TmuxSession) WaitFor(pattern string, timeout time.Duration) (string, error) {
110→	re, err := regexp.Compile(pattern)
111→	if err != nil {
112→		return "", fmt.Errorf("invalid pattern: %w", err)
113→	}
114→
115→	deadline := time.Now().Add(timeout)
116→	var matchedAt time.Time
117→	var lastStable string
118→	contentChanged := s.stableAtSend == "" // skip change requirement for initial waits
119→
120→	for time.Now().Before(deadline) {
121→		content := s.Capture()
122→		stable := stableContent(content)
123→
124→		// Bail early if the process has exited and the pattern doesn't match.
125→		if !re.MatchString(content) {
126→			if s.IsPaneDead() {
127→				return content, fmt.Errorf("process exited while waiting for %q\n--- pane content ---\n%s\n--- end pane content ---", pattern, content)
128→			}
129→			matchedAt = time.Time{}
130→			lastStable = ""
131→			time.Sleep(pollInterval)
132→			continue
133→		}
134→
135→		if !contentChanged && stable != s.stableAtSend {
136→			contentChanged = true
137→		}
138→
139→		if stable != lastStable {
140→			matchedAt = time.Now()
141→			lastStable = stable
142→			time.Sleep(pollInterval)
143→			continue
144→		}
145→
146→		if contentChanged && time.Since(matchedAt) >= settleTime {
147→			return content, nil
148→		}
149→
150→		time.Sleep(pollInterval)
151→	}
152→	content := s.Capture()
153→	return content, fmt.Errorf("timed out waiting for %q after %s\n--- pane content ---\n%s\n--- end pane content ---", pattern, timeout, content)
154→}
155→
156→// IsPaneDead returns true if the process inside the tmux pane has exited.
157→func (s *TmuxSession) IsPaneDead() bool {
158→	cmd := exec.Command("tmux", "display-message", "-t", s.name, "-p", "#{pane_dead}")
159→	out, err := cmd.Output()
160→	if err != nil {
161→		return true
162→	}
163→	return strings.TrimSpace(string(out)) == "1"
164→}
165→
166→func (s *TmuxSession) Capture() string {
167→	cmd := exec.Command("tmux", "capture-pane", "-t", s.name, "-p")
168→	out, _ := cmd.Output()
169→	return strings.TrimRight(string(out), "\n")
170→}
171→
172→func (s *TmuxSession) Close() error {
173→	for _, fn := range s.cleanups {
174→		fn()
175→	}
176→	cmd := exec.Command("tmux", "kill-session", "-t", s.name)
177→	out, err := cmd.CombinedOutput()
178→	if err != nil {
179→		return fmt.Errorf("tmux kill-session: %w\n%s", err, out)
180→	}
181→	return nil
182→}
183→
184→// shellQuote wraps s in single quotes with proper escaping for POSIX shells.
185→func shellQuote(s string) string {
186→	return "'" + strings.ReplaceAll(s, "'", "'\\''") + "'"
187→}
188→

  1→package agents
  2→
  3→import (
  4→	"context"
  5→	"errors"
