103→// ForEachAgent runs fn as a parallel subtest for every registered agent.
104→// It handles repo setup, concurrency gating, context timeout, and cleanup.
105→// The timeout is scaled by each agent's TimeoutMultiplier.
106→func ForEachAgent(t *testing.T, timeout time.Duration, fn func(t *testing.T, s *RepoState, ctx context.Context)) {
107→	t.Helper()
108→	t.Parallel()
109→	all := agents.All()
110→	if len(all) == 0 {
111→		t.Skip("no agents registered (check E2E_AGENT filter)")
112→	}
113→	for _, agent := range all {
114→		t.Run(agent.Name(), func(t *testing.T) {
115→			slotCtx := context.Background()
116→			if deadline, ok := t.Deadline(); ok {
117→				var cancel context.CancelFunc
118→				slotCtx, cancel = context.WithDeadline(slotCtx, deadline)
119→				defer cancel()
120→			}
121→			if err := agents.AcquireSlot(slotCtx, agent); err != nil {
122→				t.Fatalf("timed out waiting for agent slot: %v", err)
123→			}
124→			defer agents.ReleaseSlot(agent)
125→
126→			scaled := time.Duration(float64(timeout) * agent.TimeoutMultiplier())
127→
128→			var prevState *RepoState
129→			for attempt := range maxScenarioRestarts + 1 {
130→				s := SetupRepo(t, agent)
131→				ctx, cancel := context.WithTimeout(context.Background(), scaled)
132→
133→				if prevState != nil {
134→					prevState.skipArtifacts = true
135→				}
136→
137→				restarted := runScenario(t, s, ctx, fn)
138→				cancel()
139→
140→				if !restarted {
141→					return
142→				}
143→				prevState = s
144→				if attempt >= maxScenarioRestarts {
145→					t.Fatalf("exhausted %d scenario attempts due to transient API errors", maxScenarioRestarts+1)
146→				}
147→				t.Logf("transient error, restarting scenario (attempt %d/%d)", attempt+2, maxScenarioRestarts+1)
148→			}
149→		})
150→	}
151→}
152→
153→func runScenario(t *testing.T, s *RepoState, ctx context.Context, fn func(t *testing.T, s *RepoState, ctx context.Context)) (restarted bool) {
154→	t.Helper()
155→	defer func() {
156→		if r := recover(); r != nil {
157→			if _, ok := r.(errScenarioRestart); ok {
158→				restarted = true
159→				return
160→			}
161→			panic(r)
162→		}
163→	}()
164→	fn(t, s, ctx)
165→	return false
166→}
