174→// RunPrompt runs an agent prompt, logs the command and output to ConsoleLog,
175→// and returns the result. If the agent reports a transient API error, it
176→// panics with errScenarioRestart to trigger a full scenario restart.
177→func (s *RepoState) RunPrompt(t *testing.T, ctx context.Context, prompt string, opts ...agents.Option) (agents.Output, error) {
178→	t.Helper()
179→	out, err := s.Agent.RunPrompt(ctx, s.Dir, prompt, opts...)
180→	s.logPromptResult(out)
181→
182→	if err != nil && s.Agent.IsTransientError(out, err) {
183→		errMsg := fmt.Sprintf("transient API error (stderr: %s)", strings.TrimSpace(out.Stderr))
184→		t.Logf("%s — restarting scenario", errMsg)
185→		fmt.Fprintf(s.ConsoleLog, "> [transient] %s — restarting scenario\n", errMsg)
186→		panic(errScenarioRestart{msg: errMsg})
187→	}
188→
189→	return out, err
190→}
