229→// WaitForSessionIdle polls the session state files in .git/entire-sessions/
230→// until no session has phase "active", or fails the test after timeout.
231→func WaitForSessionIdle(t *testing.T, dir string, timeout time.Duration) {
232→	t.Helper()
233→	stateDir := filepath.Join(dir, ".git", "entire-sessions")
234→	deadline := time.Now().Add(timeout)
235→	for time.Now().Before(deadline) {
236→		entries, err := os.ReadDir(stateDir)
237→		if err != nil {
238→			time.Sleep(200 * time.Millisecond)
239→			continue
240→		}
241→		anyActive := false
242→		for _, entry := range entries {
243→			if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".json") || strings.HasSuffix(entry.Name(), ".tmp") {
244→				continue
245→			}
246→			data, err := os.ReadFile(filepath.Join(stateDir, entry.Name()))
247→			if err != nil {
248→				continue
249→			}
250→			var state struct {
251→				Phase string `json:"phase"`
252→			}
253→			if err := json.Unmarshal(data, &state); err != nil {
254→				continue
255→			}
256→			if state.Phase == "active" {
257→				anyActive = true
258→				break
259→			}
260→		}
261→		if !anyActive {
262→			return
263→		}
264→		time.Sleep(200 * time.Millisecond)
265→	}
266→	t.Fatalf("session(s) did not transition to idle within %s", timeout)
267→}
268→
269→// ValidateCheckpointDeep performs comprehensive validation of checkpoint metadata
270→// on the checkpoint branch, including transcript JSONL validity, content hash
271→// verification, and prompt content checking.
272→func ValidateCheckpointDeep(t *testing.T, dir string, v DeepCheckpointValidation) {
273→	t.Helper()
274→
275→	AssertCheckpointExists(t, dir, v.CheckpointID)
276→	AssertCheckpointMetadataComplete(t, dir, v.CheckpointID)
277→
278→	if v.Strategy != "" {
279→		meta := ReadCheckpointMetadata(t, dir, v.CheckpointID)
280→		assert.Equal(t, v.Strategy, meta.Strategy,
281→			"checkpoint %s: strategy mismatch", v.CheckpointID)
282→	}
283→
284→	if len(v.FilesTouched) > 0 {
285→		AssertCheckpointFilesTouched(t, dir, v.CheckpointID, v.FilesTouched)
286→	}
287→
288→	path := CheckpointPath(v.CheckpointID)
289→
290→	// Validate session metadata exists and has checkpoint_id
291→	sessionBlob := fmt.Sprintf("entire/checkpoints/v1:%s/0/metadata.json", path)
292→	sessionRaw := gitOutputSafe(dir, "show", sessionBlob)
293→	if assert.NotEmpty(t, sessionRaw, "session metadata should exist at %s", sessionBlob) {
294→		var sessionMeta map[string]any
295→		if assert.NoError(t, json.Unmarshal([]byte(sessionRaw), &sessionMeta)) {
296→			assert.Equal(t, v.CheckpointID, sessionMeta["checkpoint_id"],
297→				"session metadata checkpoint_id should match")
298→			assert.NotEmpty(t, sessionMeta["created_at"], "session metadata should have created_at")
299→		}
300→	}
301→
302→	// Validate transcript is valid JSONL
303→	transcriptBlob := fmt.Sprintf("entire/checkpoints/v1:%s/0/full.jsonl", path)
304→	transcriptRaw := gitOutputSafe(dir, "show", transcriptBlob)
305→	if assert.NotEmpty(t, transcriptRaw, "transcript should exist at %s", transcriptBlob) {
306→		lines := strings.Split(transcriptRaw, "\n")
307→		nonEmpty := 0
308→		for _, line := range lines {
309→			if strings.TrimSpace(line) != "" {
310→				nonEmpty++
311→			}
312→		}
313→		assert.Positive(t, nonEmpty, "transcript should have at least one line")
314→
315→		for _, expected := range v.ExpectedTranscriptContent {
316→			assert.Contains(t, transcriptRaw, expected,
317→				"transcript should contain %q", expected)
318→		}
319→
320→		// Validate content hash
321→		hashBlob := fmt.Sprintf("entire/checkpoints/v1:%s/0/content_hash.txt", path)
322→		hashRaw := gitOutputSafe(dir, "show", hashBlob)
323→		if hashRaw != "" {
324→			hash := sha256.Sum256([]byte(transcriptRaw))
325→			expectedHash := "sha256:" + hex.EncodeToString(hash[:])
326→			assert.Equal(t, expectedHash, strings.TrimSpace(hashRaw),
327→				"content hash should match transcript SHA-256")
328→		}
329→	}
330→
331→	// Validate prompt.txt if expected prompts specified
332→	if len(v.ExpectedPrompts) > 0 {
333→		promptBlob := fmt.Sprintf("entire/checkpoints/v1:%s/0/prompt.txt", path)
334→		promptRaw := gitOutputSafe(dir, "show", promptBlob)
335→		for _, expected := range v.ExpectedPrompts {
336→			assert.Contains(t, promptRaw, expected,
337→				"prompt.txt should contain %q", expected)
338→		}
339→	}
340→}
