108→	return kt
109→}
110→
111→// AddResponse adds a user prompt paired with an assistant text response.
112→func (kt *KiroTranscript) AddResponse(prompt, response string) *KiroTranscript {
113→	userContent := marshalPromptContent(prompt)
114→
115→	responseContent := map[string]interface{}{
116→		"Response": map[string]interface{}{
117→			"message_id": "msg-resp",
118→			"content":    response,
119→		},
120→	}
121→	assistantContent, _ := json.Marshal(responseContent)
122→
123→	kt.History = append(kt.History, kiroHistoryEntry{
124→		User:      kiroUserMessage{Content: userContent},
125→		Assistant: assistantContent,
126→	})
127→	return kt
128→}
129→
130→// JSON returns the JSON-encoded transcript string.
131→func (kt *KiroTranscript) JSON(t *testing.T) string {
132→	t.Helper()
133→	data, err := json.Marshal(kt)
134→	if err != nil {
135→		t.Fatalf("marshal KiroTranscript: %v", err)
136→	}
137→	return string(data)
138→}
139→
140→// WriteToFile writes the transcript to a file and returns the absolute path.
141→func (kt *KiroTranscript) WriteToFile(t *testing.T, env *TestEnv, relPath string) string {
142→	t.Helper()
143→	env.WriteFile(relPath, kt.JSON(t))
144→	return env.AbsPath(relPath)
145→}
